import { Fragment } from "react";
import { NavLink, useLocation } from "react-router-dom";
import {
    Home,
    Users,
    Calendar,
    Settings,
    LayoutGrid,
    LogOut,
    ShieldCheck,
    Briefcase,
    UserCircle,
    ScanSearch,
    KeyRound,
    PartyPopper,
    ScrollText,
    CalendarX,
} from "lucide-react";
import { useAuth } from "@/shared/AuthContext";
import { useAuditMode } from "@/shared/AuditModeContext";
import { PERMISSIONS } from "@/constants/permissions";
import { Badge } from "@/shadcn/components/ui/badge";
import { cn } from "@/shadcn/lib/utils";
import {
    Sidebar,
    SidebarContent,
    SidebarFooter,
    SidebarGroup,
    SidebarGroupContent,
    SidebarGroupLabel,
    SidebarHeader,
    SidebarMenu,
    SidebarMenuButton,
    SidebarMenuItem,
    SidebarRail,
    SidebarSeparator,
} from "@/shadcn/components/ui/sidebar";

type MenuItem = {
    icon: React.ComponentType<React.SVGProps<SVGSVGElement>>;
    label: string;
    path: string;
    permission?: string;
};

type MenuGroup = {
    label?: string;
    items: MenuItem[];
};

const menuGroups: MenuGroup[] = [
    {
        items: [
            { icon: Home, label: "Dashboard", path: "/dashboard" },
        ],
    },
    {
        label: "People & Access",
        items: [
            { icon: Users,       label: "Manage Users",        path: "/users",          permission: PERMISSIONS.Employee.Read },
            { icon: ShieldCheck, label: "Roles & Permissions", path: "/roles",          permission: PERMISSIONS.Role.Read },
            { icon: KeyRound,    label: "My Permissions",      path: "/my-permissions" },
        ],
    },
    {
        label: "Time & Leave",
        items: [
            { icon: Calendar,    label: "Work Schedule",    path: "/work-schedule",    permission: PERMISSIONS.WorkSchedule.Read },
            { icon: PartyPopper, label: "Public Holidays",  path: "/public-holidays",  permission: PERMISSIONS.PublicHoliday.Read },
            { icon: CalendarX,   label: "Leave Management", path: "/leave-management", permission: PERMISSIONS.Leave.Read },
        ],
    },
    {
        label: "Business",
        items: [
            { icon: Briefcase,  label: "Customers",   path: "/customers",   permission: PERMISSIONS.Customer.Read },
            { icon: LayoutGrid, label: "Assignments", path: "/assignments", permission: PERMISSIONS.ProjectAssignment.Read },
        ],
    },
    {
        label: "System",
        items: [
            { icon: Settings,   label: "Settings",    path: "/application-settings", permission: PERMISSIONS.ApplicationSettings.Read },
            { icon: ScrollText, label: "System Logs", path: "/logs",                 permission: PERMISSIONS.ApplicationSettings.Read },
        ],
    },
];

function NavItem({ item }: { item: MenuItem }) {
    const location = useLocation();
    const isActive = location.pathname.startsWith(item.path);

    return (
        <SidebarMenuItem>
            <SidebarMenuButton asChild isActive={isActive} tooltip={item.label} className="rounded-2xl">
                <NavLink to={item.path}>
                    <item.icon />
                    <span>{item.label}</span>
                </NavLink>
            </SidebarMenuButton>
        </SidebarMenuItem>
    );
}

export default function AppSidebar() {
    const { user, logout, hasPermission } = useAuth();
    const { isAuditMode, toggleAuditMode } = useAuditMode();
    const { pathname } = useLocation();
    const isAdmin = user?.role === "Admin";

    const filteredGroups = menuGroups
        .map(group => ({
            ...group,
            items: group.items.filter(item => !item.permission || hasPermission(item.permission)),
        }))
        .filter(group => group.items.length > 0);

    return (
        <Sidebar collapsible="icon">
            <SidebarHeader>
                <SidebarMenu>
                    <SidebarMenuItem>
                        <SidebarMenuButton size="lg" asChild className="rounded-2xl">
                            <NavLink to="/">
                                <div className="flex aspect-square size-8 shrink-0 items-center justify-center rounded-xl bg-gradient-to-br from-primary to-primary/60 text-primary-foreground shadow-lg shadow-primary/20">
                                    <span className="text-base font-black italic">H</span>
                                </div>
                                <span className="font-black text-xl tracking-tight text-sidebar-foreground leading-none">
                                    HARMONY
                                </span>
                            </NavLink>
                        </SidebarMenuButton>
                    </SidebarMenuItem>
                </SidebarMenu>
            </SidebarHeader>

            <SidebarContent className="py-2 overflow-x-hidden">
                {filteredGroups.map((group, index) => (
                    <Fragment key={group.label ?? "__main__"}>
                        {index > 0 && <SidebarSeparator />}
                        <SidebarGroup>
                            {group.label && (
                                <SidebarGroupLabel className="text-[10px] font-bold uppercase tracking-widest text-sidebar-foreground/40 px-2 mb-0.5">
                                    {group.label}
                                </SidebarGroupLabel>
                            )}
                            <SidebarGroupContent>
                                <SidebarMenu>
                                    {group.items.map(item => (
                                        <NavItem key={item.path} item={item} />
                                    ))}
                                </SidebarMenu>
                            </SidebarGroupContent>
                        </SidebarGroup>
                    </Fragment>
                ))}
            </SidebarContent>

            <SidebarFooter className="border-t border-sidebar-border p-3">
                <SidebarMenu>
                    <SidebarMenuItem>
                        <SidebarMenuButton
                            asChild
                            size="lg"
                            isActive={pathname === "/profile"}
                            tooltip={user?.fullName || "Profile"}
                            className="rounded-2xl h-auto py-2"
                        >
                            <NavLink to="/profile">
                                <div className="flex size-8 shrink-0 items-center justify-center rounded-xl bg-sidebar-accent border border-sidebar-border text-sidebar-foreground/60">
                                    <UserCircle className="size-5" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <p className="text-sm font-black text-sidebar-foreground truncate">
                                        {user?.fullName || user?.email?.split("@")[0] || "Guest"}
                                    </p>
                                    <Badge
                                        variant="secondary"
                                        className="mt-1 opacity-70 bg-sidebar-accent text-sidebar-foreground/70 border-sidebar-border text-[10px] px-2 py-0.5 h-auto font-bold uppercase tracking-wider rounded-full"
                                    >
                                        {user?.role || "USER"}
                                    </Badge>
                                </div>
                            </NavLink>
                        </SidebarMenuButton>
                    </SidebarMenuItem>

                    {isAdmin && (
                        <SidebarMenuItem>
                            <SidebarMenuButton
                                onClick={toggleAuditMode}
                                tooltip={isAuditMode ? "Audit Mode: ON" : "Audit Mode"}
                                className={cn(
                                    "rounded-2xl",
                                    isAuditMode
                                        ? "text-amber-400 bg-amber-500/10 border border-amber-500/20 hover:bg-amber-500/15"
                                        : "text-sidebar-foreground/50 hover:text-sidebar-foreground hover:bg-sidebar-accent"
                                )}
                            >
                                <ScanSearch className="size-4 shrink-0" />
                                <span>Audit Mode</span>
                                {isAuditMode && (
                                    <span className="ml-auto size-1.5 rounded-full bg-amber-400 animate-pulse" />
                                )}
                            </SidebarMenuButton>
                        </SidebarMenuItem>
                    )}

                    <SidebarMenuItem>
                        <SidebarMenuButton
                            onClick={logout}
                            tooltip="Sign Out"
                            className="rounded-2xl text-rose-500 hover:bg-rose-500/10 hover:text-rose-400"
                        >
                            <LogOut className="size-4" />
                            <span>Sign Out</span>
                        </SidebarMenuButton>
                    </SidebarMenuItem>
                </SidebarMenu>
            </SidebarFooter>

            <SidebarRail />
        </Sidebar>
    );
}
